pattern = r'(export const fallbackProducts: Product\[\] = \[).*?(\];)'
new_content = re.sub(pattern, r'\1\n' + products_data + r'\2', content, flags=re.DOTALL)

with open('src/lib/products.ts', 'w') as f:
    f.write(new_content)

# Update professionals.ts
